evaluators.evaluation_logic:
const checkpoints = [];
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const readingList = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

const jumpingTag = tags.find(t => t.name === 'Jumping' || t.slug === 'jumping');
const jumpingTagId = jumpingTag ? jumpingTag.id : null;

let qualifyingArticles = [];
if (jumpingTagId) {
  qualifyingArticles = articles.filter(a =>
    a.category === 'training' &&
    Array.isArray(a.tagIds) &&
    a.tagIds.includes(jumpingTagId) &&
    new Date(a.published_at).getFullYear() === 2024
  );
  qualifyingArticles.sort((a, b) => new Date(b.published_at) - new Date(a.published_at));
}

const firstThreeIds = qualifyingArticles.slice(0, 3).map(a => a.id);
const savedIds = readingList.map(item => item.articleId);
const qualifyingSavedCount = firstThreeIds.filter(id => savedIds.includes(id)).length;

[1, 2, 3].forEach((n) => {
  const weight = n < 3 ? 0.33 : 0.34;
  checkpoints.push({
    passed: firstThreeIds.length >= n && qualifyingSavedCount >= n,
    weight: weight
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const comments = JSON.parse(localStorage.getItem('comments') || '[]');

const lamenessTag = tags.find(t => t.name === 'Lameness' || t.slug === 'lameness');
const lamenessTagId = lamenessTag ? lamenessTag.id : null;

let targetArticleId = null;
if (lamenessTagId) {
  const healthLameness = articles.filter(a =>
    a.category === 'health' &&
    Array.isArray(a.tagIds) &&
    a.tagIds.includes(lamenessTagId)
  );
  healthLameness.sort((a, b) => new Date(b.published_at) - new Date(a.published_at));
  if (healthLameness.length > 0) {
    targetArticleId = healthLameness[0].id;
  }
}

let qualifyingCount = 0;
if (targetArticleId) {
  qualifyingCount = comments.filter(c => {
    if (c.articleId !== targetArticleId) return false;
    if (c.author_name !== 'Guest Rider') return false;
    if (c.author_email !== 'guest@example.com') return false;
    const body = (c.body || '');
    const words = body.trim().split(/\s+/).filter(Boolean);
    if (words.length < 30) return false;
    const lower = body.toLowerCase();
    if (!lower.includes('training schedule')) return false;
    if (!lower.includes('vet visit')) return false;
    return true;
  }).length;
}

checkpoints.push({ passed: qualifyingCount >= 1, weight: 1.0 });

return checkPoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_articles') || '[]');

let targetArticleId = null;
const comp2023 = articles.filter(a =>
  a.category === 'competitions' &&
  new Date(a.published_at).getFullYear() === 2023
);
comp2023.sort((a, b) => new Date(a.published_at) - new Date(b.published_at));
if (comp2023.length > 0) {
  targetArticleId = comp2023[0].id;
}

let qualifyingFavCount = 0;
if (targetArticleId) {
  qualifyingFavCount = favorites.filter(f => f.articleId === targetArticleId).length;
}

checkpoints.push({ passed: qualifyingFavCount >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

const qualifyingSubs = subs.filter(s =>
  s.name === 'Horse Fan' &&
  s.email === 'horse_fan@example.com' &&
  s.frequency === 'weekly' &&
  (s.email_format === 'html' || s.email_format === 'HTML') &&
  s.wants_training_tips === true &&
  s.wants_competition_updates === true &&
  s.wants_merchandise_offers === false
);

checkpoints.push({ passed: qualifyingSubs.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const readingList = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const groupedFlag = JSON.parse(localStorage.getItem('task5_readingListGroupedByCategory') || 'null');

let counts = { training: 0, health: 0, gear: 0 };
readingList.forEach(item => {
  const art = articles.find(a => a.id === item.articleId);
  if (!art) return;
  if (Object.prototype.hasOwnProperty.call(counts, art.category)) {
    counts[art.category]++;
  }
});

const correctCounts = (
  counts.training === 2 &&
  counts.health === 2 &&
  counts.gear === 1 &&
  (counts.training + counts.health + counts.gear) === 5
);

// CP1: Correct mix and total of reading list items
checkpoints.push({ passed: correctCounts, weight: 0.7 });
// CP2: Reading list grouped by category, only rewarded if counts are also correct
checkpoints.push({ passed: groupedFlag === true && correctCounts, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');

const oatsTag = tags.find(t => t.name === 'Oats Feeding' || t.slug === 'oats-feeding');
const oatsTagId = oatsTag ? oatsTag.id : null;

let targetArticle = null;
if (oatsTagId) {
  const candidates = articles.filter(a =>
    a.category === 'health' &&
    Array.isArray(a.tagIds) &&
    a.tagIds.includes(oatsTagId)
  );
  if (candidates.length > 0) {
    targetArticle = candidates[0];
  }
}

let qualifyingCount = 0;
if (targetArticle) {
  qualifyingCount = messages.filter(m => {
    if (m.name !== 'Alex Rider') return false;
    if (m.email !== 'alex@example.com') return false;
    if (m.subject !== 'Question about oats feeding schedule') return false;
    if (m.inquiry_type !== 'nutrition_advice') return false;
    if (m.relatedArticleId !== targetArticle.id) return false;
    if (m.related_article_published_date_text !== targetArticle.display_published_date) return false;
    const body = (m.message || '');
    const words = body.trim().split(/\s+/).filter(Boolean);
    if (words.length < 40) return false;
    if (!body.toLowerCase().includes('oats')) return false;
    return true;
  }).length;
}

checkpoints.push({ passed: qualifyingCount >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const polls = JSON.parse(localStorage.getItem('polls') || '[]');
const pollOptions = JSON.parse(localStorage.getItem('poll_options') || '[]');
const pollVotes = JSON.parse(localStorage.getItem('poll_votes') || '[]');
const comments = JSON.parse(localStorage.getItem('comments') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');

// Find the first tricks training article (newest first)
const tricksTag = tags.find(t => t.name === 'Tricks' || t.slug === 'tricks');
const tricksTagId = tricksTag ? tricksTag.id : null;
let tricksArticleId = null;
if (tricksTagId) {
  const candidates = articles.filter(a =>
    a.category === 'training' &&
    Array.isArray(a.tagIds) &&
    a.tagIds.includes(tricksTagId)
  );
  candidates.sort((a, b) => new Date(b.published_at) - new Date(a.published_at));
  if (candidates.length > 0) {
    tricksArticleId = candidates[0].id;
  }
}

// Find the tricks poll and its 'Bow' option
const poll = polls.find(p => p.question && p.question.indexOf('Which trick should Star learn next?') !== -1);
let bowOptionId = null;
if (poll) {
  const options = pollOptions.filter(o => o.pollId === poll.id);
  const bowOption = options.find(o => o.label === 'Bow' || o.value === 'bow');
  bowOptionId = bowOption ? bowOption.id : null;
}

// Check for a new vote for Bow in this poll (ids starting with 'vote_')
let hasBowVote = false;
if (poll && bowOptionId) {
  hasBowVote = pollVotes.some(v =>
    v.pollId === poll.id &&
    v.optionId === bowOptionId &&
    typeof v.id === 'string' &&
    v.id.startsWith('vote_')
  );
}

// Check for qualifying comment on the tricks article
let hasQualifyingComment = false;
if (tricksArticleId) {
  hasQualifyingComment = comments.some(c => {
    if (c.articleId !== tricksArticleId) return false;
    if (c.author_name !== 'Trick Voter') return false;
    if (c.author_email !== 'voter@example.com') return false;
    const body = (c.body || '');
    const words = body.trim().split(/\s+/).filter(Boolean);
    if (words.length < 20) return false;
    if (!body.toLowerCase().includes('bow')) return false;
    return true;
  });
}

checkpoints.push({ passed: hasBowVote, weight: 0.5 });
checkpoints.push({ passed: hasQualifyingComment, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const photos = JSON.parse(localStorage.getItem('photos') || '[]');
const favPhotos = JSON.parse(localStorage.getItem('favorite_photos') || '[]');

// Filter to 2022 competition photos
let galleryPhotos = photos.filter(p => p.year === 2022 && p.category === 'competitions');
// Sort by taken_at desc, then id, matching BusinessLogic.getGalleryPhotos
galleryPhotos = galleryPhotos.slice().sort((a, b) => {
  const da = new Date(a.taken_at || 0).getTime();
  const db = new Date(b.taken_at || 0).getTime();
  if (da !== db) return db - da;
  if (a.id < b.id) return -1;
  if (a.id > b.id) return 1;
  return 0;
});

// Choose every other photo starting from the first: indices 0,2,4,6 (up to 4 photos)
const targetPhotoIds = [];
for (let i = 0; i < galleryPhotos.length && targetPhotoIds.length < 4; i += 2) {
  targetPhotoIds.push(galleryPhotos[i].id);
}

const favoritedIds = favPhotos.map(f => f.photoId);
const qualifyingFavCount = targetPhotoIds.filter(id => favoritedIds.includes(id)).length;

[1, 2, 3, 4].forEach(n => {
  checkpoints.push({
    passed: targetPhotoIds.length >= n && qualifyingFavCount >= n,
    weight: 0.25
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
